// src/utils/formatMessage.js

export function formatMessage(text) {
  if (!text) return "";

  // Escape HTML first to prevent injection
  const escaped = text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");

  // Bold: **bold**
  const bolded = escaped.replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>");

  // Italic: *italic*
  const italicized = bolded.replace(/\*(.*?)\*/g, "<em>$1</em>");

  // Links: [OpenAI](https://openai.com)
  const linked = italicized.replace(
    /\[(.*?)\]\((https?:\/\/[^\s]+)\)/g,
    `<a href="$2" target="_blank" class="text-blue-600 underline">$1</a>`
  );

  return linked;
}
